import React, { useState } from 'react';
import { Table, Button, Modal, Form, Space, Input } from 'antd';
import { useTable, useFilters, useGlobalFilter } from 'react-table';
import { DefaultColumnFilter } from './DefaultColumnFilter';

const MaterialList = ({ material }) => {
  const [isAddModalVisible, setIsAddModalVisible] = useState(false);
  const [isEditModalVisible, setIsEditModalVisible] = useState(false);
  const [newMaterialData, setNewMaterialData] = useState({});
  const [editMaterialData, setEditMaterialData] = useState({});

  const handleAddMaterial = () => {
    // Add material logic
  };

  const handleEditMaterial = () => {
    // Edit material logic
  };

  const handleDeleteMaterial = (id) => {
    // Delete material logic
  };

  const handleAddClick = () => {
    setIsAddModalVisible(true);
  };

  const handleEditClick = (data) => {
    setEditMaterialData(data);
    setIsEditModalVisible(true);
  };

  const handleAddModalCancel = () => {
    setIsAddModalVisible(false);
  };

  const handleEditModalCancel = () => {
    setIsEditModalVisible(false);
  };

  const columns = [
    {
      Header: 'ID',
      accessor: 'matid',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Name',
      accessor: 'name',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Description',
      accessor: 'description',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Unit of Measure',
      accessor: 'unit_of_measure',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Price per Unit',
      accessor: 'price_per_unit',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Recent Vendor',
      accessor: 'recent_vendor',
      Filter: DefaultColumnFilter,
    },
    {
      Header: 'Actions',
      Cell: ({ row }) => (
        <Space size="middle">
          <Button type="primary" onClick={() => handleEditClick(row.original)}>
            Edit
          </Button>
          <Button type="primary" danger onClick={() => handleDeleteMaterial(row.original.id)}>
            Delete
          </Button>
        </Space>
      ),
    },
  ];

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    state,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: material,
      initialState: { pageIndex: 0 },
    },
    useFilters,
    useGlobalFilter
  );

  const { globalFilter } = state;

  const handleGlobalFilterChange = useAsyncDebounce((value) => {
    setGlobalFilter(value || undefined);
  }, 200);

  return (
    <div>
      <div className="table-toolbar">
        <Button type="primary" onClick={handleAddClick}>
          Add Material
        </Button>
        <Input.Search
          placeholder="Search materials"
          allowClear
          value={globalFilter || ''}
          onChange={(e) => handleGlobalFilterChange(e.target.value)}
          style={{ width: 200, float: 'right' }}
        />
      </div>
      <Table {...getTableProps()} dataSource={rows} rowKey="id">
        {headerGroups.map((headerGroup) => (
          <Table.ColumnGroup {...headerGroup.getHeaderGroupProps()}>
            {headerGroup.headers.map((column) => (
              <Table.HeaderCell {...column.getHeaderProps()}>{column.render('Header')}</Table.HeaderCell>
            ))}
          </Table.ColumnGroup>
        ))}
        <Table.Body {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <Table.Row {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <Table.Cell {...cell.getCellProps()}>{cell.render('Cell')}</Table.Cell>
                ))}
              </Table.Row>
            );
          })}
        </Table.Body>
      </Table>
      <Modal
        title="Add Material"
        visible={isAddModalVisible}
        onOk={handleAddMaterial}
        onCancel={handleAddModalCancel}
      >
        <Form>
          {/* Add Material form fields */}
        </Form>
      </Modal>
      <Modal
        title="Edit Material"
        visible={isEditModalVisible}
        onOk={handleEditMaterial}
        onCancel={handleEditModalCancel}
      >
        <Form>
          {/* Edit Material form fields */}
        </Form>
      </Modal>
    </div>
  );
};

export default MaterialList;
